// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract PaymentSplitter is Initializable {
    address public developerAddress;
    address public merchantAddress;
    uint256 public feeBps; // 100 = 1%

    // Substitui o construtor
    function initialize(address _developer, address _merchant, uint256 _feeBps) public initializer {
        developerAddress = _developer;
        merchantAddress = _merchant;
        feeBps = _feeBps;
    }

    // Função de pagamento limpa e otimizada
    function processPayment(address token, uint256 amount) external {
        uint256 fee = (amount * feeBps) / 10000;
        uint256 merchantAmount = amount - fee;

        // O remetente (msg.sender) já deve ter dado Approve() no frontend
        IERC20(token).transferFrom(msg.sender, developerAddress, fee);
        IERC20(token).transferFrom(msg.sender, merchantAddress, merchantAmount);
    }
}

