// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/proxy/Clones.sol";
import "./PaymentSplitter.sol";

contract SplitterFactory {
    address public immutable implementationContract;
    address public developerAddress;

    // Evento crucial para o seu backend Go "escutar"
    event MerchantOnboarded(address indexed merchant, address cloneAddress);

    constructor(address _implementation, address _developer) {
        implementationContract = _implementation;
        developerAddress = _developer;
    }

    // Seu Backend Go chama essa função ao cadastrar um novo lojista
    function createMerchantClone(address _merchant, uint256 _feeBps) external returns (address) {
        // EIP-1167: Cria o clone magicamente com um custo mínimo de gás
        address clone = Clones.clone(implementationContract);

        // Inicializa o clone com os dados específicos deste lojista
        PaymentSplitter(clone).initialize(developerAddress, _merchant, _feeBps);

        emit MerchantOnboarded(_merchant, clone);
        return clone;
    }
}

