// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/proxy/utils/Initializable.sol";

interface ISplitterFactory {
    function developerAddress() external view returns (address);
    function feeBps() external view returns (uint256);
    function isRouterAllowed(address router) external view returns (bool);
    function paused() external view returns (bool);
    function recordPayment(bytes32 paymentId) external;
    function owner() external view returns (address);
}

contract SplitterLogic is ReentrancyGuard, EIP712, Initializable {
    using ECDSA for bytes32;

    address public merchantAddress;
    address public factory;
    address public authorizer;

    bytes32 public constant AUTHORIZED_PAYMENT_TYPEHASH = keccak256(
        "AuthorizedPayment(bytes32 paymentId,address token,uint256 amount,uint256 expiry)"
    );

    event PaymentProcessed(
        bytes32 indexed paymentId,
        address indexed tokenIn,
        address indexed tokenOut,
        uint256 amountIn,
        uint256 merchantReceived,
        uint256 devFee
    );
    event AuthorizerUpdated(address indexed newAuthorizer);

    error AlreadyInitialized();
    error ZeroAddress();
    error PaymentAlreadyProcessed();
    error PaymentExpired();
    error InvalidSignature();
    error FactoryPaused();
    error RouterNotAllowed();
    error SlippageExceeded();
    error TransferFailed();
    error OnlyFactory();

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() EIP712("NeoPaymentSplitter", "1") {
        _disableInitializers();
    }

    function initialize(address _merchantAddress, address _factory, address _authorizer) public initializer {
        if (_merchantAddress == address(0) || _factory == address(0)) revert ZeroAddress();

        merchantAddress = _merchantAddress;
        factory = _factory;
        authorizer = _authorizer;
    }

    function payDirect(
        bytes32 paymentId,
        address token,
        uint256 amount,
        uint256 expiry,
        bytes calldata signature
    ) external nonReentrant {
        if (block.timestamp > expiry) revert PaymentExpired();

        _verifyPaymentSignature(paymentId, token, amount, expiry, signature);

        ISplitterFactory fac = ISplitterFactory(factory);
        if (fac.paused()) revert FactoryPaused();
        if (fac.owner() == address(0)) revert ZeroAddress(); // Sanity check

        if (ISplitterFactory(factory).recordPayment.selector != 0) {
            // This is just to ensure factory interaction is logged
        }

        uint256 feeBps = fac.feeBps();
        uint256 fee = (amount * feeBps) / 10000;
        uint256 merchantAmount = amount - fee;

        // Record payment at factory level (prevents double spend across clones if using same paymentId)
        fac.recordPayment(paymentId);

        if (!IERC20(token).transferFrom(msg.sender, fac.developerAddress(), fee)) revert TransferFailed();
        if (!IERC20(token).transferFrom(msg.sender, merchantAddress, merchantAmount)) revert TransferFailed();

        emit PaymentProcessed(paymentId, token, token, amount, merchantAmount, fee);
    }

    function payWithSwap(
        bytes32 paymentId,
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut,
        uint256 expiry,
        address router,
        address spender,
        bytes calldata swapData,
        bytes calldata signature
    ) external nonReentrant {
        if (block.timestamp > expiry) revert PaymentExpired();

        _verifyPaymentSignature(paymentId, tokenIn, amountIn, expiry, signature);

        ISplitterFactory fac = ISplitterFactory(factory);
        if (fac.paused()) revert FactoryPaused();
        if (!fac.isRouterAllowed(router)) revert RouterNotAllowed();

        if (!IERC20(tokenIn).transferFrom(msg.sender, address(this), amountIn)) revert TransferFailed();
        IERC20(tokenIn).approve(spender, amountIn);

        uint256 balanceBefore = IERC20(tokenOut).balanceOf(address(this));
        (bool success, ) = router.call(swapData);
        if (!success) revert TransferFailed();

        uint256 receivedOut = IERC20(tokenOut).balanceOf(address(this)) - balanceBefore;
        if (receivedOut < minAmountOut) revert SlippageExceeded();

        uint256 feeBps = fac.feeBps();
        uint256 fee = (receivedOut * feeBps) / 10000;
        uint256 merchantAmount = receivedOut - fee;

        fac.recordPayment(paymentId);

        if (!IERC20(tokenOut).transfer(fac.developerAddress(), fee)) revert TransferFailed();
        if (!IERC20(tokenOut).transfer(merchantAddress, merchantAmount)) revert TransferFailed();

        emit PaymentProcessed(paymentId, tokenIn, tokenOut, amountIn, merchantAmount, fee);
    }

    function _verifyPaymentSignature(
        bytes32 paymentId,
        address token,
        uint256 amount,
        uint256 expiry,
        bytes calldata signature
    ) internal view {
        if (authorizer == address(0)) return; // No signature required if authorizer is not set

        bytes32 structHash = keccak256(
            abi.encode(
                AUTHORIZED_PAYMENT_TYPEHASH,
                paymentId,
                token,
                amount,
                expiry
            )
        );

        bytes32 hash = _hashTypedDataV4(structHash);
        address recovered = hash.recover(signature);

        if (recovered != authorizer) revert InvalidSignature();
    }

    function setAuthorizer(address _newAuthorizer) external {
        if (msg.sender != factory) revert OnlyFactory();
        authorizer = _newAuthorizer;
        emit AuthorizerUpdated(_newAuthorizer);
    }

    function rescueToken(address token, uint256 amount) external {
        if (msg.sender != factory) revert OnlyFactory();
        address owner = ISplitterFactory(factory).owner();
        if (!IERC20(token).transfer(owner, amount)) revert TransferFailed();
    }
}

